INSERT INTO notices (id, title, content, category, author_id, pinned, created_at, updated_at) VALUES (E'568f72d8-b2f7-4b7c-93e9-ab90eb1a4281', E'2026년 상반기 신입사원 온보딩 일정 안내', E'2026년 상반기 신입사원 여러분, 환영합니다!\n\n■ 온보딩 일정\n- 1주차: 회사소개, 정보보안 교육, 사내 시스템 안내\n- 2주차: 부서 배치 및 멘토 매칭, 업무용 PC 세팅\n- 3~4주차: 실무 적응 및 첫 과제 수행\n\n■ 필수 이수 항목\n- 정보보안 교육 (온라인, 30분)\n- 준법감시 교육 (온라인, 1시간)\n- 사내 시스템 권한 신청\n\n문의: 인사팀 (내선 2000)', E'인사', E'471d9b97-6884-479c-a450-4f9beba0c44b', true, E'2026-04-08 16:27:31.888468+09:00', E'2026-04-08 16:27:31.888468+09:00');
INSERT INTO notices (id, title, content, category, author_id, pinned, created_at, updated_at) VALUES (E'8b6bfc76-2392-433a-99e8-78ea3a3299d2', E'전사 정보보안 교육 실시 안내 (필수)', E'전 임직원 대상 연 1회 정보보안 교육을 아래와 같이 실시합니다.\n\n- 기간: 2026.04.07 ~ 2026.04.18\n- 방법: 온라인 교육 (인트라넷 → 인사시스템 → 교육)\n- 소요시간: 약 30분\n- 미이수 시 인사평가 반영\n\n보안 관련 문의: ICT부문 정보보안팀', E'보안', E'471d9b97-6884-479c-a450-4f9beba0c44b', true, E'2026-04-08 16:27:31.888468+09:00', E'2026-04-08 16:27:31.888468+09:00');
INSERT INTO notices (id, title, content, category, author_id, pinned, created_at, updated_at) VALUES (E'ad23f2fd-ff74-4d27-a3ef-19a08c6e7752', E'법인카드 사용 기준 변경 안내', E'4월부터 법인카드 사용 기준이 변경됩니다.\n\n■ 주요 변경 사항\n- 심야(23시 이후) 사용 시 사유서 필수 첨부\n- 접대비 건당 한도: 30만원\n- 월 누적 한도 초과 시 팀장 사전승인 필요\n\n상세 기준은 인트라넷 → 경영지원 → 법인카드 가이드를 참고해 주세요.', E'경영지원', E'471d9b97-6884-479c-a450-4f9beba0c44b', false, E'2026-04-08 16:27:31.888468+09:00', E'2026-04-08 16:27:31.888468+09:00');
INSERT INTO notices (id, title, content, category, author_id, pinned, created_at, updated_at) VALUES (E'e3086613-7645-469f-bd18-5dec199711e2', E'업무용 택시 서비스(카카오T 비즈니스) 이용 안내', E'업무용 택시 서비스 이용 절차를 안내드립니다.\n\n■ 이용 가능 시간\n- 야근: 21시 이후 (팀장 사전승인)\n- 외근: 업무 시간 내 (사유 기재)\n- 출장: 공항/역 이동 시\n\n■ 신청 방법\n1. 카카오T 비즈니스 앱 설치\n2. 회사 이메일로 가입\n3. 총무팀에서 승인 후 이용 가능\n\n문의: 전략기획부문 총무팀', E'총무', E'471d9b97-6884-479c-a450-4f9beba0c44b', false, E'2026-04-08 16:27:31.888468+09:00', E'2026-04-08 16:27:31.888468+09:00');
INSERT INTO notices (id, title, content, category, author_id, pinned, created_at, updated_at) VALUES (E'c589dbd8-154b-4783-9386-ad597a0bf282', E'4월 사내 식당 메뉴 리뉴얼 안내', E'4월부터 사내 식당 메뉴가 리뉴얼됩니다.\n\n- 샐러드바 상시 운영\n- 저염식 메뉴 추가\n- 간식 코너 운영시간: 14:00~16:00\n\n식단은 인트라넷 → 총무 게시판에서 매주 월요일 업데이트됩니다.', E'총무', E'471d9b97-6884-479c-a450-4f9beba0c44b', false, E'2026-04-08 16:27:31.888468+09:00', E'2026-04-08 16:27:31.888468+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'9b90baa9-b20f-4bcb-81e1-62756a848924', E'a6f10f79-9dc2-4ed7-8b0e-2575d988000c', E'471d9b97-6884-479c-a450-4f9beba0c44b', E'IT 시스템 권한 신청 안내', E'전호철님,\n\nIT 시스템 권한 신청 방법 안내드립니다.\n\n■ 신청 경로\n인트라넷 상단 → 인사시스템 → IT 서비스 데스크 → 권한 신청\n\n■ 필수 신청 항목\n- 그룹웨어/메일 계정\n- VPN 접속 권한\n- ERP 시스템 접근\n- 업무 관련 DB 접근 (팀장 승인 필요)\n\n모든 권한은 소속 팀장 승인 후 IT 지원팀에서 처리됩니다.\n\n이소현 드림', E'이소현 사원 (인사팀) <lsh0003@kiwoom.com>', E'전호철 사원 (주식운용팀) <jhc0001@kiwoom.com>', E'', true, false, false, false, E'2026-04-08 16:27:31.892428+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'00fbe0c3-68e9-4f4f-8b2a-f0e0536ac30b', E'a6f10f79-9dc2-4ed7-8b0e-2575d988000c', E'471d9b97-6884-479c-a450-4f9beba0c44b', E'환영합니다! 신입사원 온보딩 안내', E'전호철님, 인사팀 이소현입니다.\n\n입사를 축하드립니다! 온보딩 일정을 안내드립니다.\n\n■ 이번 주 필수 사항\n1. 업무용 PC 프로그램 설치 (HTS, 보안 프로그램 등)\n2. 인트라넷 → 인사시스템 → IT 서비스 데스크에서 권한 신청\n3. 정보보안 교육 이수\n\n궁금한 점은 언제든 문의해 주세요!\n\n이소현 드림', E'이소현 사원 (인사팀) <lsh0003@kiwoom.com>', E'전호철 사원 (주식운용팀) <jhc0001@kiwoom.com>', E'', true, true, false, false, E'2026-04-08 16:27:31.892428+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'20c70d47-c749-41ad-a9a1-088e52b54869', E'4041e00c-b195-4969-80c7-21d52d8c7e93', E'd0025145-df46-4e15-adf3-96b660d2cb6c', E'[공유] 정보보안팀·컴플라이언스팀 사전 협의 결과', E'안녕하십니까, 채널기획팀 채영희입니다. 업무에 노고가 많으십니다.\n\n킥오프 결과에 따른 액션 아이템 진행 결과를 공유드립니다.\n\n[정보보안팀 소셜 로그인 OAuth 검토 의뢰 결과]\n· 검토 가능 시점: 5월 초 (현재 다른 긴급 보안 과제 병행으로 약 3주 소요 예상)\n· 검토 범위: OAuth 2.0 적용 시 보안 취약점 분석, 추가 인증 레이어 필요 여부\n· 담당자: 정보보안팀 차현석 차장 (chs0061@kiwoom.com)\n→ 중기 일정(7월 목표)에는 영향 없으나, 소셜 로그인 기능은 2차 릴리즈로 분리 검토 필요\n\n[컴플라이언스팀 협의 결과]\n· 금융소비자보호법상 적합성 확인은 로그인·회원가입 단계가 아닌\n  금융상품 가입 단계에서 진행되므로 이번 개선 범위에서 별도 제약 없음\n· 단, 세그먼트 분기 시 "연령 기반 화면 차별화"에 대한 법무 의견서 확보 권고\n  → 법무1팀에 추가 검토 의뢰 예정\n\n일정 조정이 필요한 부분은 4월 21일 TF 회의에서 논의하겠습니다.\n\n많이 바쁘시겠지만 확인 부탁드리겠습니다.\n\n===================================================\n키움증권 채널기획팀  채영희 과장\n\n서울특별시 영등포구 의사당대로 96 (TP타워, 여의도동)\nE-mail : coh0077@kiwoom.com\nTel    : 02-768-3864\n===================================================', E'채영희 과장 (채널기획팀)  <coh0077@kiwoom.com>', E'진강연 사원 (인사이트랩팀); 천규리 과장 (플랫폼전략팀); 제민재 과장 (SQUAD)  <jky0002@kiwoom.com; cgr0774@kiwoom.com; jmj0634@kiwoom.com>', E'신다현 부장 (채널기획팀장); 안홍철 부장 (인사이트랩팀장); 김건 부장 (플랫폼전략팀장); 남재호 차장 (SQUAD장)  <sdh0075@kiwoom.com; ahc0712@kiwoom.com; kg0764@kiwoom.com; njh0633@kiwoom.com>', true, false, false, false, E'2026-04-16 11:45:00+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'd87b3b06-5701-4d53-88be-cb444063f146', E'd0025145-df46-4e15-adf3-96b660d2cb6c', E'4041e00c-b195-4969-80c7-21d52d8c7e93', E'[문의] 영웅문 S# 회원가입·로그인 화면 고객 세그먼트별 개선 제안', E'안녕하십니까, 인사이트랩팀 진강연입니다. 업무에 노고가 많으십니다.\n\n다름이 아니라, 영웅문 S# 회원가입 및 로그인 파트 개선과 관련하여 의견을 여쭤보고자 메일 드립니다.\n\n저희 인사이트랩팀에서 최근 고객 투자 행동 데이터를 분석한 결과, 영웅문 S# 신규 가입자 중\n약 40%가 회원가입 화면에서 이탈하고 있으며, 특히 50대 이상 고객의 이탈률이\n20·30대 대비 약 2.3배 높은 것으로 나타났습니다.\n\n이에 고객 세그먼트에 따라 회원가입·로그인 화면을 다른 형태로 구성하면\n이탈률을 개선할 수 있을 것으로 판단하고 있습니다.\n\n[세그먼트별 화면 구성 아이디어]\n· 20-30대 (디지털 네이티브): 간편 인증(카카오·네이버 소셜 로그인) 전면 배치, 최소 입력 필드\n· 40-50대 (전환기 투자자): 공동인증서 로그인 강조, 단계별 안내 문구 강화\n· 60대 이상 (시니어): 큰 글씨·고대비 UI, ARS 본인인증 대체 옵션 제공\n\n각 과장님께서 채널 기획·플랫폼 전략·개발 관점에서 검토 의견 주시면 감사하겠습니다.\n\n많이 바쁘시겠지만 확인 부탁드리겠습니다.\n\n===================================================\n키움증권 인사이트랩팀  진강연 사원\n\n서울특별시 영등포구 의사당대로 96 (TP타워, 여의도동)\nE-mail : jky0002@kiwoom.com\nTel    : 02-768-2240\n===================================================', E'진강연 사원 (인사이트랩팀)  <jky0002@kiwoom.com>', E'채영희 과장 (채널기획팀); 천규리 과장 (플랫폼전략팀); 제민재 과장 (SQUAD)  <coh0077@kiwoom.com; cgr0774@kiwoom.com; jmj0634@kiwoom.com>', E'안홍철 부장 (인사이트랩팀장); 신다현 부장 (채널기획팀장); 김건 부장 (플랫폼전략팀장); 남재호 차장 (SQUAD장)  <ahc0712@kiwoom.com; sdh0075@kiwoom.com; kg0764@kiwoom.com; njh0633@kiwoom.com>', true, false, false, false, E'2026-04-08 09:32:00+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'b3af94bd-4573-4b03-a4ae-db1c244ab554', E'd0025145-df46-4e15-adf3-96b660d2cb6c', E'4041e00c-b195-4969-80c7-21d52d8c7e93', E'RE: [문의] 영웅문 S# 회원가입·로그인 — 논의 요약 및 킥오프 일정 제안', E'안녕하십니까, 인사이트랩팀 진강연입니다. 업무에 노고가 많으십니다.\n\n세 분의 전문적인 의견 진심으로 감사드립니다. 논의 내용을 아래와 같이 정리하였습니다.\n\n[논의 결과 요약]\n  · 세그먼트 감지: 본인인증(PASS) 후 생년월일 기반 자동 분기\n  · 구현 방식: 피처 플래그 기반 A/B 테스트 연동 (방안 A)\n  · 단기: 큰 글씨 옵션 + "처음 이용하시나요?" 버튼 강화 (1스프린트 내)\n  · 중기: 세그먼트별 회원가입·로그인 전면 개편\n  · 선행 협의: 정보보안팀 소셜 로그인 검토 / 컴플라이언스팀 적합성 확인 연계\n\n[킥오프 미팅 제안]\n  · 일시: 2026년 4월 14일(화) 오후 2시 ~ 3시\n  · 장소: 대회의실 B (키움증권 인트라넷 → 자원관리 → 회의실 예약)\n  · 안건: ① 세그먼트 기준 정의  ② 단기 과제 일정 확정  ③ 중기 TF 구성 논의\n\n일정 확인 후 회신 부탁드립니다.\n\n많이 바쁘시겠지만 확인 부탁드리겠습니다.\n\n===================================================\n키움증권 인사이트랩팀  진강연 사원\n\n서울특별시 영등포구 의사당대로 96 (TP타워, 여의도동)\nE-mail : jky0002@kiwoom.com\nTel    : 02-768-2240\n===================================================', E'진강연 사원 (인사이트랩팀)  <jky0002@kiwoom.com>', E'채영희 과장 (채널기획팀); 천규리 과장 (플랫폼전략팀); 제민재 과장 (SQUAD)  <coh0077@kiwoom.com; cgr0774@kiwoom.com; jmj0634@kiwoom.com>', E'안홍철 부장 (인사이트랩팀장); 신다현 부장 (채널기획팀장); 김건 부장 (플랫폼전략팀장); 남재호 차장 (SQUAD장)  <ahc0712@kiwoom.com; sdh0075@kiwoom.com; kg0764@kiwoom.com; njh0633@kiwoom.com>', true, false, false, false, E'2026-04-10 09:55:00+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'cc527180-9ac9-4387-a61d-1304d6be0b89', E'd0025145-df46-4e15-adf3-96b660d2cb6c', E'a6f10f79-9dc2-4ed7-8b0e-2575d988000c', E'[온보딩 설문] 진강연님 0분기(~1개월) 설문 결과', E'진강연님의 0분기(~1개월) 온보딩 설문 결과입니다.\n\n■ 5점 척도 결과\n• Q1. 팀내 인원들의 이름과 직급을 다 외웠는가: 4점\n• Q2. 사내 메일과 장비들을 받았는가: 5점\n• Q3. 업무를 시작할 환경이 다 갖추어졌는가: 3점\n• 평균: 4.0점\n\n■ 주관식\nQ. 적응해 나아가는 본인의 모습을 상상하여 앞으로의 포부를 간단하게 적어주세요\nA. 2개월동안 다양한 업무를 배우면서 이제 좀 적응한 것 같습니다. 앞으로 실제 업무를 맡아보면서 성장하고 싶습니다.\n\n■ AI 분석\n감정: 긍정적이고 자신감 있는 모습이 느껴집니다. 적응에 대한 만족감과 앞으로의 성장에 대한 기대가 담겨 있습니다.\n\n핵심 키워드: 적응, 성장, 다양한 업무, 실제 업무\n\n요약: 신입사원은 2개월 동안 다양한 업무를 배우며 적응해 나가고 있으며, 앞으로 실제 업무를 맡아 성장하고 싶다는 포부를 가지고 있습니다. \n\n📄 출처: 온보딩 설문 분석 — 주관식 답변 분석', E'진강연 (온보딩 설문 자동 발송)', E'이소현 (인사팀)', E'', true, false, true, false, E'2026-04-09 10:54:10.746261+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'54479985-f070-410d-bc3e-4b060870832a', E'9ca49754-4b16-45de-ac8f-6a87212c6f01', E'd0025145-df46-4e15-adf3-96b660d2cb6c', E'RE: [문의] 영웅문 S# 회원가입·로그인 화면 고객 세그먼트별 개선 제안', E'안녕하십니까, 플랫폼전략팀 천규리입니다. 업무에 노고가 많으십니다.\n\n진강연 사원님 제안 및 채영희 과장님 의견 잘 검토하였습니다. 플랫폼 전략 관점 의견 드립니다.\n\n[플랫폼 전략 관점 검토]\n\n1. 전략적 방향성\n   이번 제안은 단순 UI 개선을 넘어 영웅문 플랫폼 개인화 고도화 전략과 맥락을 같이합니다.\n   올해 추진 중인 ''신규 사용자 온보딩 Flow 개선'' 과제와 연계가 효율적입니다.\n\n2. 플랫폼 수준 정의 필요 사항\n   · 세그먼트 정의 기준 (연령·거래 이력·투자 성향 등 복합 기준 검토)\n   · 세그먼트 재분류 주기 (가입 시 1회 고정 vs. 이용 패턴 기반 동적 변경)\n   · A/B 테스트 프레임워크 구축 (전환율 측정 기준 정의 포함)\n\n3. 경쟁사 벤치마킹\n   토스·카카오페이증권은 이미 가입 단계부터 투자 성향 수집 → 홈 화면 개인화 중입니다.\n   이번 기회에 가입 퍼널 전반 경험 재설계를 고려해볼 만합니다.\n\n킥오프 미팅 구성을 제안드립니다. 가능하신 일정 회신 부탁드립니다.\n\n많이 바쁘시겠지만 확인 부탁드리겠습니다.\n\n===================================================\n키움증권 플랫폼전략팀  천규리 과장\n\n서울특별시 영등포구 의사당대로 96 (TP타워, 여의도동)\nE-mail : cgr0774@kiwoom.com\nTel    : 02-768-4004\n===================================================', E'천규리 과장 (플랫폼전략팀)  <cgr0774@kiwoom.com>', E'진강연 사원 (인사이트랩팀); 채영희 과장 (채널기획팀); 제민재 과장 (SQUAD)  <jky0002@kiwoom.com; coh0077@kiwoom.com; jmj0634@kiwoom.com>', E'김건 부장 (플랫폼전략팀장); 안홍철 부장 (인사이트랩팀장); 신다현 부장 (채널기획팀장); 남재호 차장 (SQUAD장)  <kg0764@kiwoom.com; ahc0712@kiwoom.com; sdh0075@kiwoom.com; njh0633@kiwoom.com>', true, false, false, false, E'2026-04-09 10:08:00+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'a6718d8f-6fee-4c55-9fa5-31a123c0e17e', E'1e9dddea-1240-42b9-987a-0f96e866e604', E'd0025145-df46-4e15-adf3-96b660d2cb6c', E'RE: [문의] 영웅문 S# 회원가입·로그인 화면 고객 세그먼트별 개선 제안', E'안녕하십니까, SQUAD 제민재입니다. 업무에 노고가 많으십니다.\n\n진강연 사원님, 채영희·천규리 과장님 의견 잘 확인하였습니다. 개발(SQUAD) 관점 의견 드립니다.\n\n[개발 관점 검토]\n\n1. 기술 구현 방식\n   · 방안 A — 피처 플래그(Feature Flag): 세그먼트 판별을 서버에서 내려주고 클라이언트 분기\n     → A/B 테스트·점진적 배포(Canary Release)에 유리 / 예상 공수: 3~4스프린트\n   · 방안 B — 세그먼트별 독립 컴포넌트 개발: UI 자유도 높으나 유지보수 비용 증가\n     → 예상 공수: 5~7스프린트\n   → A/B 테스트 연동 감안 시 방안 A 권장합니다.\n\n2. 사전 협의 필요 사항\n   · 정보보안팀: 소셜 로그인 OAuth 2.0 보안 검토 (최소 2주 소요 예상)\n   · 컴플라이언스팀: 금융소비자보호법 적합성 확인 연계 방안\n   · QA: 세그먼트별 테스트 케이스 약 200개 작성 필요\n\n3. 개발 일정 제안 (기획 확정 기준)\n   1~2스프린트: 세그먼트 판별 API + 피처 플래그 인프라 구축\n   3~4스프린트: 세그먼트별 화면 개발 및 QA\n   5스프린트: A/B 테스트 모니터링 및 점진적 배포\n\n킥오프 미팅 적극 참여하겠습니다.\n\n많이 바쁘시겠지만 확인 부탁드리겠습니다.\n\n===================================================\n키움증권 SQUAD  제민재 과장\n\n서울특별시 영등포구 의사당대로 96 (TP타워, 여의도동)\nE-mail : jmj0634@kiwoom.com\nTel    : 02-768-5830\n===================================================', E'제민재 과장 (SQUAD)  <jmj0634@kiwoom.com>', E'진강연 사원 (인사이트랩팀); 채영희 과장 (채널기획팀); 천규리 과장 (플랫폼전략팀)  <jky0002@kiwoom.com; coh0077@kiwoom.com; cgr0774@kiwoom.com>', E'남재호 차장 (SQUAD장); 안홍철 부장 (인사이트랩팀장); 신다현 부장 (채널기획팀장); 김건 부장 (플랫폼전략팀장)  <njh0633@kiwoom.com; ahc0712@kiwoom.com; sdh0075@kiwoom.com; kg0764@kiwoom.com>', true, false, false, false, E'2026-04-09 15:47:00+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'dacdfa4f-a0da-47a4-8735-9307efa95715', E'd0025145-df46-4e15-adf3-96b660d2cb6c', E'4041e00c-b195-4969-80c7-21d52d8c7e93', E'[사전 공유] 영웅문 S# 세그먼트별 이탈률 분석 자료', E'안녕하십니까, 인사이트랩팀 진강연입니다. 업무에 노고가 많으십니다.\n\n채영희 과장님 요청하신 고객 데이터 분석 자료를 킥오프 전 공유드립니다.\n\n[분석 결과 요약 — 영웅문 S# 회원가입·로그인 퍼널 (2025 Q4 기준)]\n\n■ 회원가입 단계별 이탈률\n  1단계 본인인증    : 이탈률 12%  (연령대별 차이 미미)\n  2단계 약관 동의   : 이탈률 18%  (60대+ 이탈률 31% — 가장 높음)\n  3단계 정보 입력   : 이탈률 25%  (50대+ 이탈률 38%)\n  4단계 계좌 개설   : 이탈률 15%  (전 연령대 유사)\n\n■ 연령대별 가입 완료율\n  20대: 71%   30대: 68%   40대: 54%   50대: 41%   60대+: 29%\n\n■ 로그인 방식별 사용 비율\n  공동인증서: 44%   간편비밀번호: 31%   생체인증: 22%   기타: 3%\n  → 60대+는 공동인증서 비율 78% (간편비밀번호 15%, 생체인증 7%)\n\n■ 시사점\n  · 약관 동의·정보 입력 단계의 시니어 이탈이 핵심 문제\n  · 세그먼트별 UX 최적화 시 가입 완료율 최소 8~12%p 개선 가능 (추정)\n\n킥오프에서 원본 데이터 상세 공유하겠습니다.\n\n많이 바쁘시겠지만 확인 부탁드리겠습니다.\n\n===================================================\n키움증권 인사이트랩팀  진강연 사원\n\n서울특별시 영등포구 의사당대로 96 (TP타워, 여의도동)\nE-mail : jky0002@kiwoom.com\nTel    : 02-768-2240\n===================================================', E'진강연 사원 (인사이트랩팀)  <jky0002@kiwoom.com>', E'채영희 과장 (채널기획팀); 천규리 과장 (플랫폼전략팀); 제민재 과장 (SQUAD)  <coh0077@kiwoom.com; cgr0774@kiwoom.com; jmj0634@kiwoom.com>', E'안홍철 부장 (인사이트랩팀장); 신다현 부장 (채널기획팀장); 김건 부장 (플랫폼전략팀장); 남재호 차장 (SQUAD장)  <ahc0712@kiwoom.com; sdh0075@kiwoom.com; kg0764@kiwoom.com; njh0633@kiwoom.com>', true, false, false, false, E'2026-04-11 15:22:00+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'd90db6ad-7e6a-4d29-a43c-03d09e91d28d', E'd0025145-df46-4e15-adf3-96b660d2cb6c', E'4041e00c-b195-4969-80c7-21d52d8c7e93', E'[킥오프 결과] 영웅문 S# 회원가입·로그인 세그먼트 개선 TF 구성 및 과제 확정', E'안녕하십니까, 인사이트랩팀 진강연입니다. 업무에 노고가 많으십니다.\n\n오늘 킥오프에 참석해 주셔서 감사합니다. 논의 결과를 공유드립니다.\n\n[킥오프 결과 — 2026.04.14]\n\n■ TF 구성 확정\n  · TF명: 영웅문 S# UX 개인화 TF\n  · TF장: 천규리 과장 (플랫폼전략팀)\n  · 멤버: 채영희 과장 (채널기획팀), 제민재 과장 (SQUAD), 진강연 사원 (인사이트랩팀)\n\n■ 과제 확정\n  [단기 — 4월 말 목표]\n  · 시니어 큰 글씨 옵션 추가 (제민재 과장 SQUAD 1스프린트)\n  · "처음 이용하시나요?" 버튼 UI 강화 (채영희 과장 기획 → 제민재 과장 개발)\n\n  [중기 — 7월 목표]\n  · 세그먼트별 회원가입·로그인 화면 전면 개편\n  · 피처 플래그 인프라 구축 (제민재 과장 주도)\n  · 온보딩 Flow 개선 과제 연계 (천규리 과장 주도)\n\n■ 선행 액션 아이템\n  · 채영희 과장: 정보보안팀 소셜 로그인 OAuth 검토 의뢰 (4/15까지)\n  · 채영희 과장: 컴플라이언스팀 금융소비자보호법 적합성 확인 협의 요청 (4/15까지)\n  · 제민재 과장: 피처 플래그 인프라 기술 검토 문서 작성 (4/21까지)\n  · 천규리 과장: 세그먼트 정의 기준 초안 작성 (4/18까지)\n  · 진강연 사원: 세그먼트별 이탈 원인 심층 분석 (4/21까지)\n\n다음 TF 회의는 4월 21일(화) 오후 2시로 잡겠습니다.\n\n많이 바쁘시겠지만 확인 부탁드리겠습니다.\n\n===================================================\n키움증권 인사이트랩팀  진강연 사원\n\n서울특별시 영등포구 의사당대로 96 (TP타워, 여의도동)\nE-mail : jky0002@kiwoom.com\nTel    : 02-768-2240\n===================================================', E'진강연 사원 (인사이트랩팀)  <jky0002@kiwoom.com>', E'채영희 과장 (채널기획팀); 천규리 과장 (플랫폼전략팀); 제민재 과장 (SQUAD)  <coh0077@kiwoom.com; cgr0774@kiwoom.com; jmj0634@kiwoom.com>', E'안홍철 부장 (인사이트랩팀장); 신다현 부장 (채널기획팀장); 김건 부장 (플랫폼전략팀장); 남재호 차장 (SQUAD장)  <ahc0712@kiwoom.com; sdh0075@kiwoom.com; kg0764@kiwoom.com; njh0633@kiwoom.com>', true, false, false, false, E'2026-04-14 16:05:00+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'd992f05f-6f2d-4616-86e0-cb8fa5d331a5', E'1e9dddea-1240-42b9-987a-0f96e866e604', E'd0025145-df46-4e15-adf3-96b660d2cb6c', E'RE: 영웅문 S# 회원가입·로그인 — 킥오프 확인 및 기술 사전 검토 공유', E'안녕하십니까, SQUAD 제민재입니다. 업무에 노고가 많으십니다.\n\n4월 14일(화) 오후 2시 참석 가능합니다.\n\n기술 관점에서 킥오프 전 사전 검토 내용을 공유드립니다.\n\n[SQUAD 사전 기술 검토 결과]\n\n1. 현재 영웅문 S# 아키텍처 현황\n   · 클라이언트: React Native 0.72 (iOS/Android 공용)\n   · 인증 모듈: 현행 공동인증서·PASS·생체인증 지원 (소셜 로그인 미지원)\n   · 피처 플래그 인프라: 현재 미구축 상태 — 킥오프 확정 시 별도 스프린트 필요\n\n2. 단기 과제 선착수 가능 항목 (기획 없이 착수 가능)\n   · 시니어 전용 큰 글씨 옵션: 시스템 접근성 설정 연동으로 1스프린트 내 구현 가능\n   · "처음 이용하시나요?" 버튼 UI 강화: 0.5스프린트 예상\n\n3. 중기 과제 의존성 정리\n   · 세그먼트 분기 로직 → 피처 플래그 인프라 구축 선행 필요\n   · 소셜 로그인 → 정보보안팀 OAuth 검토 완료 후 착수 가능\n   · A/B 테스트 → 리테일Biz분석팀과 전환율 측정 기준 사전 협의 필요\n\n킥오프에서 상세 논의하겠습니다. 자료 취합해서 당일 공유 예정입니다.\n\n많이 바쁘시겠지만 확인 부탁드리겠습니다.\n\n===================================================\n키움증권 SQUAD  제민재 과장\n\n서울특별시 영등포구 의사당대로 96 (TP타워, 여의도동)\nE-mail : jmj0634@kiwoom.com\nTel    : 02-768-5830\n===================================================', E'제민재 과장 (SQUAD)  <jmj0634@kiwoom.com>', E'진강연 사원 (인사이트랩팀); 채영희 과장 (채널기획팀); 천규리 과장 (플랫폼전략팀)  <jky0002@kiwoom.com; coh0077@kiwoom.com; cgr0774@kiwoom.com>', E'남재호 차장 (SQUAD장); 안홍철 부장 (인사이트랩팀장); 신다현 부장 (채널기획팀장); 김건 부장 (플랫폼전략팀장)  <njh0633@kiwoom.com; ahc0712@kiwoom.com; sdh0075@kiwoom.com; kg0764@kiwoom.com>', true, false, false, false, E'2026-04-11 09:10:00+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'c2f9a11c-3098-4a23-af80-30028bd17bad', E'd0025145-df46-4e15-adf3-96b660d2cb6c', E'4041e00c-b195-4969-80c7-21d52d8c7e93', E'[사전 공유] 세그먼트별 이탈 원인 심층 분석 결과 — 2차 TF 회의 안건', E'안녕하십니까, 인사이트랩팀 진강연입니다. 업무에 노고가 많으십니다.\n\n오늘 2차 TF 회의 전 심층 분석 결과 공유드립니다.\n\n[세그먼트별 이탈 원인 심층 분석 — 인사이트랩팀]\n\n■ 세그먼트 C (60세 이상) 주요 이탈 원인 분석\n  · 약관 동의 화면 (이탈률 31%):\n    - 글씨 크기 불만족: 고령층 VOC 중 42%가 "글씨가 너무 작다" 언급\n    - 약관 분량 과다: 평균 스크롤 횟수 9.2회 (전체 평균 3.1회 대비 3배)\n  · 정보 입력 화면 (이탈률 38%):\n    - 공동인증서 오류: "인증서를 찾을 수 없습니다" 에러 발생 비율 18%\n    - 입력 필드 수 과다: 14개 필드 (경쟁사 토스 4개 대비 3.5배)\n\n■ 세그먼트 A (20~39세) 주요 불편 사항\n  · 소셜 로그인 부재: 신규 가입 포기 이유 1위 "또 가입해야 하는 게 번거롭다" (34%)\n  · 생체인증 초기 설정 유도 미흡: 설정 완료율 41% (타사 평균 67%)\n\n■ 공통 개선 필요 사항\n  · 약관 동의 UX: 핵심 약관 요약 + 전체 보기 분리 구조 도입 권고\n  · 오류 메시지 개선: 기술적 오류 코드 → 사용자 이해 가능한 안내 문구로 변경\n\n오늘 TF에서 이 내용을 바탕으로 우선순위를 논의하겠습니다.\n\n많이 바쁘시겠지만 확인 부탁드리겠습니다.\n\n===================================================\n키움증권 인사이트랩팀  진강연 사원\n\n서울특별시 영등포구 의사당대로 96 (TP타워, 여의도동)\nE-mail : jky0002@kiwoom.com\nTel    : 02-768-2240\n===================================================', E'진강연 사원 (인사이트랩팀)  <jky0002@kiwoom.com>', E'채영희 과장 (채널기획팀); 천규리 과장 (플랫폼전략팀); 제민재 과장 (SQUAD)  <coh0077@kiwoom.com; cgr0774@kiwoom.com; jmj0634@kiwoom.com>', E'안홍철 부장 (인사이트랩팀장); 신다현 부장 (채널기획팀장); 김건 부장 (플랫폼전략팀장); 남재호 차장 (SQUAD장)  <ahc0712@kiwoom.com; sdh0075@kiwoom.com; kg0764@kiwoom.com; njh0633@kiwoom.com>', true, false, false, false, E'2026-04-21 09:45:00+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'5c829c92-8bc1-4cd0-b747-561915bfd860', E'9ca49754-4b16-45de-ac8f-6a87212c6f01', E'd0025145-df46-4e15-adf3-96b660d2cb6c', E'[공유] 고객 세그먼트 정의 기준 초안', E'안녕하십니까, 플랫폼전략팀 천규리입니다. 업무에 노고가 많으십니다.\n\n세그먼트 정의 기준 초안을 공유드립니다. 진강연 사원님 데이터 분석을 반영하였습니다.\n\n[고객 세그먼트 정의 기준 — 초안 v0.1]\n\n■ 1차 기준: 연령 (본인인증 생년월일 기반)\n  · 세그먼트 A (디지털 네이티브): ~39세\n  · 세그먼트 B (전환기 투자자): 40~59세\n  · 세그먼트 C (시니어): 60세 이상\n\n■ 화면 구성 방향 (안)\n  세그먼트 A:\n    - 소셜 로그인(카카오·네이버) 전면 배치 (보안 검토 후 적용)\n    - 간편비밀번호·생체인증 기본 설정 유도\n    - 최소 입력 필드, 빠른 진행 UX\n\n  세그먼트 B:\n    - 공동인증서·PASS 균형 배치\n    - 주요 기능 간략 소개 (투자 정보, 자산 조회)\n    - 고객센터 연결 버튼 중단 배치\n\n  세그먼트 C:\n    - 큰 글씨·고대비 UI (WCAG 2.1 AA 기준)\n    - ARS 본인인증 대체 옵션 상단 배치\n    - 단계별 안내 문구 강화, 단순 화면 구성\n    - 고객센터 연결 버튼 최상단 배치\n\n■ 향후 고도화 방향\n  2차 기준으로 거래 이력·투자 성향을 추가하여 동적 세그먼트 전환 검토 예정\n\n21일 TF 회의에서 피드백 부탁드립니다.\n\n많이 바쁘시겠지만 확인 부탁드리겠습니다.\n\n===================================================\n키움증권 플랫폼전략팀  천규리 과장\n\n서울특별시 영등포구 의사당대로 96 (TP타워, 여의도동)\nE-mail : cgr0774@kiwoom.com\nTel    : 02-768-4004\n===================================================', E'천규리 과장 (플랫폼전략팀)  <cgr0774@kiwoom.com>', E'진강연 사원 (인사이트랩팀); 채영희 과장 (채널기획팀); 제민재 과장 (SQUAD)  <jky0002@kiwoom.com; coh0077@kiwoom.com; jmj0634@kiwoom.com>', E'김건 부장 (플랫폼전략팀장); 안홍철 부장 (인사이트랩팀장); 신다현 부장 (채널기획팀장); 남재호 차장 (SQUAD장)  <kg0764@kiwoom.com; ahc0712@kiwoom.com; sdh0075@kiwoom.com; njh0633@kiwoom.com>', true, false, false, false, E'2026-04-18 14:55:00+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'952d754a-e968-4f18-9893-f3acaf1d9c3a', E'1e9dddea-1240-42b9-987a-0f96e866e604', E'd0025145-df46-4e15-adf3-96b660d2cb6c', E'[공유] 피처 플래그 인프라 기술 검토 문서 (초안)', E'안녕하십니까, SQUAD 제민재입니다. 업무에 노고가 많으십니다.\n\n피처 플래그 인프라 기술 검토 문서 초안을 공유드립니다.\n\n[피처 플래그 인프라 기술 검토 — 초안]\n\n1. 도입 방안 비교\n   ┌─────────────┬─────────────────────┬─────────────────────┐\n   │  구분        │  자체 개발           │  외부 솔루션 도입    │\n   ├─────────────┼─────────────────────┼─────────────────────┤\n   │  개발 공수   │  약 2스프린트        │  약 0.5스프린트      │\n   │  비용        │  초기 개발비         │  월 구독료 발생      │\n   │  유연성      │  높음               │  제공 기능 내 제한   │\n   │  보안        │  사내 정책 적용 용이 │  외부 의존도 존재    │\n   └─────────────┴─────────────────────┴─────────────────────┘\n   → 보안 정책 준수·비용 고려 시 자체 개발 권장\n\n2. 자체 개발 시 구현 방향\n   · 세그먼트 판별: 서버 API에서 사용자 연령 기반 세그먼트 키 반환\n   · 클라이언트 분기: React Native 컨텍스트로 전체 앱에서 세그먼트 값 활용\n   · 관리 어드민: 운영팀이 플래그 On/Off 및 비율 조정 가능한 간단한 내부 관리 화면\n\n3. 예상 일정 (4/21 TF 승인 시)\n   4/22 ~ 5/2:  피처 플래그 서버 API 개발\n   5/5 ~ 5/16:  클라이언트 연동 및 관리 어드민 개발\n   5/19 ~ 5/23: QA 및 스테이징 환경 검증\n\n21일 TF 회의에서 방향 확정 부탁드립니다.\n\n많이 바쁘시겠지만 확인 부탁드리겠습니다.\n\n===================================================\n키움증권 SQUAD  제민재 과장\n\n서울특별시 영등포구 의사당대로 96 (TP타워, 여의도동)\nE-mail : jmj0634@kiwoom.com\nTel    : 02-768-5830\n===================================================', E'제민재 과장 (SQUAD)  <jmj0634@kiwoom.com>', E'진강연 사원 (인사이트랩팀); 채영희 과장 (채널기획팀); 천규리 과장 (플랫폼전략팀)  <jky0002@kiwoom.com; coh0077@kiwoom.com; cgr0774@kiwoom.com>', E'남재호 차장 (SQUAD장); 안홍철 부장 (인사이트랩팀장); 신다현 부장 (채널기획팀장); 김건 부장 (플랫폼전략팀장)  <njh0633@kiwoom.com; ahc0712@kiwoom.com; sdh0075@kiwoom.com; kg0764@kiwoom.com>', true, false, false, false, E'2026-04-18 10:20:00+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'0642cfaa-4009-425e-ac5d-3bdbe37cf1c5', E'd0025145-df46-4e15-adf3-96b660d2cb6c', E'4041e00c-b195-4969-80c7-21d52d8c7e93', E'[제안] A/B 테스트 지표 설계 및 성공 기준 제안 — 5/7 TF 사전 공유', E'안녕하십니까, 인사이트랩팀 진강연입니다. 업무에 노고가 많으십니다.\n\n내일 TF 회의 전 A/B 테스트 지표 설계 제안을 사전 공유드립니다.\n\n[A/B 테스트 지표 설계 제안 — 인사이트랩팀]\n\n■ 테스트 구조\n  · Control Group (기존): 현행 단일 UI 화면 (전체 신규 가입자 중 30%)\n  · Treatment Group (개선): 세그먼트별 분기 화면 (전체 신규 가입자 중 70%)\n  · 테스트 기간: 배포 후 4주 (통계적 유의성 확보 기준)\n\n■ 주요 측정 지표 (KPI)\n  [1차 지표 — 핵심 성과]\n    · 가입 완료율: 현행 대비 +8%p 이상 개선 목표\n    · 세그먼트 C (60대+) 가입 완료율: 현행 29% → 40% 이상 목표\n\n  [2차 지표 — 품질 지표]\n    · 각 단계별 이탈률\n    · 가입 소요 시간 (전체 평균 및 세그먼트별)\n    · 첫 로그인까지 소요 시간\n\n  [3차 지표 — 장기 지표]\n    · 가입 후 30일 내 첫 거래 전환율\n    · 가입 후 30일 내 앱 재방문율\n\n■ 데이터 수집 및 분석\n  · 인사이트랩팀에서 A/B 테스트 기간 중 주간 현황 모니터링 담당 예정\n  · 제민재 과장님 Sprint 5(A/B 테스트 셋업) 시 이벤트 트래킹 항목 반영 요청\n\n내일 TF에서 지표 기준 확정 부탁드립니다. 잘 부탁드립니다.\n\n많이 바쁘시겠지만 확인 부탁드리겠습니다.\n\n===================================================\n키움증권 인사이트랩팀  진강연 사원\n\n서울특별시 영등포구 의사당대로 96 (TP타워, 여의도동)\nE-mail : jky0002@kiwoom.com\nTel    : 02-768-2240\n===================================================', E'진강연 사원 (인사이트랩팀)  <jky0002@kiwoom.com>', E'채영희 과장 (채널기획팀); 천규리 과장 (플랫폼전략팀); 제민재 과장 (SQUAD)  <coh0077@kiwoom.com; cgr0774@kiwoom.com; jmj0634@kiwoom.com>', E'안홍철 부장 (인사이트랩팀장); 신다현 부장 (채널기획팀장); 김건 부장 (플랫폼전략팀장); 남재호 차장 (SQUAD장)  <ahc0712@kiwoom.com; sdh0075@kiwoom.com; kg0764@kiwoom.com; njh0633@kiwoom.com>', true, false, false, false, E'2026-05-06 13:58:00+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'9518c655-60da-4e6f-9aa5-dec007438ce1', E'9ca49754-4b16-45de-ac8f-6a87212c6f01', E'd0025145-df46-4e15-adf3-96b660d2cb6c', E'[공유] 온보딩 Flow 개선 과제 연계 방안 확정', E'안녕하십니까, 플랫폼전략팀 천규리입니다. 업무에 노고가 많으십니다.\n\n온보딩 Flow 개선 과제와의 연계 방안이 확정되어 공유드립니다.\n\n[온보딩 Flow 개선 과제 연계 방안 — 확정]\n\n■ 연계 구조 (안)\n  회원가입 완료\n      ↓ (세그먼트 판별 — 피처 플래그)\n  세그먼트별 맞춤 첫 화면 진입\n      ↓\n  세그먼트 A: 관심 섹터 선택 → 맞춤 종목 추천 화면\n  세그먼트 B: 투자 목적 선택 → 자산 현황 요약 화면\n  세그먼트 C: 주요 기능 3가지 간략 가이드 → 고객센터 연결\n\n■ 세그먼트 컨텍스트 공유 방식\n  · 피처 플래그에서 반환하는 세그먼트 키를 앱 전역 컨텍스트로 관리\n  · 온보딩 화면·메인 화면·콘텐츠 추천 모두 동일 세그먼트 키 활용\n  → 제민재 과장님 Sprint 1 API 설계 시 반영 요청 드립니다.\n\n■ 온보딩 과제 일정\n  · 5/5~5/16: 세그먼트별 온보딩 화면 기획 완료\n  · 5/19~5/30: 중기 Sprint 3과 병행 개발 예정\n\n제민재 과장님, API 설계 시 세그먼트 컨텍스트 공유 구조 반영 가능 여부 확인 부탁드립니다.\n\n많이 바쁘시겠지만 확인 부탁드리겠습니다.\n\n===================================================\n키움증권 플랫폼전략팀  천규리 과장\n\n서울특별시 영등포구 의사당대로 96 (TP타워, 여의도동)\nE-mail : cgr0774@kiwoom.com\nTel    : 02-768-4004\n===================================================', E'천규리 과장 (플랫폼전략팀)  <cgr0774@kiwoom.com>', E'진강연 사원 (인사이트랩팀); 채영희 과장 (채널기획팀); 제민재 과장 (SQUAD)  <jky0002@kiwoom.com; coh0077@kiwoom.com; jmj0634@kiwoom.com>', E'김건 부장 (플랫폼전략팀장); 안홍철 부장 (인사이트랩팀장); 신다현 부장 (채널기획팀장); 남재호 차장 (SQUAD장)  <kg0764@kiwoom.com; ahc0712@kiwoom.com; sdh0075@kiwoom.com; njh0633@kiwoom.com>', true, false, false, false, E'2026-05-02 10:05:00+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'2e50f5b0-802d-434f-a395-52c4de17e509', E'4041e00c-b195-4969-80c7-21d52d8c7e93', E'd0025145-df46-4e15-adf3-96b660d2cb6c', E'[완료 보고] 단기 과제 완료 및 법무 의견서 접수', E'안녕하십니까, 채널기획팀 채영희입니다. 업무에 노고가 많으십니다.\n\n단기 과제 완료 현황 및 법무 의견서 결과를 공유드립니다.\n\n[단기 과제 완료 현황 — 2026.04.30 기준]\n\n■ 시니어 큰 글씨 옵션 (제민재 과장 개발 완료 ✅)\n  → 4/25 스테이징 배포 완료 / 5/2 운영 반영 예정\n\n■ "처음 이용하시나요?" 버튼 UI 강화 (완료 ✅)\n  → 버튼 크기 1.5배 확대, 색상 대비 강화 (WCAG 기준 적용)\n\n■ 약관 동의 UX 개선 (완료 ✅)\n  → 핵심 약관 3줄 요약 + "전체 보기" 접기/펼치기 구조 적용\n\n[법무1팀 의견서 접수 결과]\n  · 연령 기반 세그먼트 화면 차별화: 법률적 제약 없음 (차별 금지법 해당 없음)\n  · 단, 세그먼트 분기 기준·화면 구성 내용이 공시 대상이 아님을 확인\n  · 세그먼트 정보 수집·활용 내역은 개인정보 처리방침에 명시 권고\n\n중기 개발 추진에 법률적 장애 없음을 확인하였습니다.\n5월 7일 TF 회의에서 중기 Sprint 1 진행 현황을 공유하겠습니다.\n\n많이 바쁘시겠지만 확인 부탁드리겠습니다.\n\n===================================================\n키움증권 채널기획팀  채영희 과장\n\n서울특별시 영등포구 의사당대로 96 (TP타워, 여의도동)\nE-mail : coh0077@kiwoom.com\nTel    : 02-768-3864\n===================================================', E'제민재 과장 (SQUAD)  <jmj0634@kiwoom.com>', E'진강연 사원 (인사이트랩팀); 채영희 과장 (채널기획팀); 천규리 과장 (플랫폼전략팀)  <jky0002@kiwoom.com; coh0077@kiwoom.com; cgr0774@kiwoom.com>', E'남재호 차장 (SQUAD장); 안홍철 부장 (인사이트랩팀장); 신다현 부장 (채널기획팀장); 김건 부장 (플랫폼전략팀장)  <njh0633@kiwoom.com; ahc0712@kiwoom.com; sdh0075@kiwoom.com; kg0764@kiwoom.com>', true, false, false, false, E'2026-04-30 16:10:00+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'b472d15c-f85f-4b84-ab30-742458354ba4', E'4041e00c-b195-4969-80c7-21d52d8c7e93', E'd0025145-df46-4e15-adf3-96b660d2cb6c', E'[사전 공유] 경쟁사 MTS 회원가입 UX 벤치마킹 자료', E'안녕하십니까, 채널기획팀 채영희입니다. 업무에 노고가 많으십니다.\n\n오늘 킥오프 앞서 벤치마킹 자료 공유드립니다.\n\n[경쟁사 MTS 회원가입 UX 비교 분석]\n\n■ 토스증권\n  · 토스 기존 계정 연동으로 회원가입 2단계 완료 (계좌 개설 포함 약 3분)\n  · 별도 세그먼트 분기 없으나 온보딩 완료 후 투자 성향 퀴즈 진행\n  · 강점: 극단적 단순화 / 약점: 금융투자 비경험자 대상 안내 부족\n\n■ 카카오페이증권\n  · 카카오 계정 기반 소셜 로그인 원터치 가입\n  · 가입 시 "투자 목적" 선택 → 메인 화면 콘텐츠 개인화 연동\n  · 강점: 온보딩-개인화 연계 우수 / 약점: 고령층 카카오 계정 미보유자 이탈\n\n■ 삼성증권 MTS\n  · 세그먼트 분기 없는 단일 UI 유지\n  · 대신 고령자 전용 ARS 개설 채널 별도 운영 (메인 화면 하단 배너 안내)\n  · 강점: 안정성 / 약점: MZ세대 이탈률 높음\n\n■ 영웅문 S# 차별화 방향 (안)\n  · 타사와 달리 세그먼트별 화면 자체를 다르게 구성하는 것이 차별점\n  · 단, 카카오페이증권의 온보딩-개인화 연계 구조는 참고할 만함\n\n오늘 킥오프에서 상세 논의하겠습니다. 잘 부탁드립니다.\n\n많이 바쁘시겠지만 확인 부탁드리겠습니다.\n\n===================================================\n키움증권 채널기획팀  채영희 과장\n\n서울특별시 영등포구 의사당대로 96 (TP타워, 여의도동)\nE-mail : coh0077@kiwoom.com\nTel    : 02-768-3864\n===================================================', E'채영희 과장 (채널기획팀)  <coh0077@kiwoom.com>', E'진강연 사원 (인사이트랩팀); 천규리 과장 (플랫폼전략팀); 제민재 과장 (SQUAD)  <jky0002@kiwoom.com; cgr0774@kiwoom.com; jmj0634@kiwoom.com>', E'신다현 부장 (채널기획팀장); 안홍철 부장 (인사이트랩팀장); 김건 부장 (플랫폼전략팀장); 남재호 차장 (SQUAD장)  <sdh0075@kiwoom.com; ahc0712@kiwoom.com; kg0764@kiwoom.com; njh0633@kiwoom.com>', true, false, false, false, E'2026-04-14 09:30:00+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'3515a04c-38c9-4e97-9808-df00245ef3a5', E'4041e00c-b195-4969-80c7-21d52d8c7e93', E'd0025145-df46-4e15-adf3-96b660d2cb6c', E'RE: 영웅문 S# 회원가입·로그인 — 킥오프 일정 확인 및 사전 준비 공유', E'안녕하십니까, 채널기획팀 채영희입니다. 업무에 노고가 많으십니다.\n\n진강연 사원님, 깔끔하게 정리해 주셔서 감사합니다.\n4월 14일(화) 오후 2시 참석 가능합니다.\n\n[채널기획팀 사전 준비 내용]\n1. 현행 회원가입 퍼널 분석 자료 준비 (단계별 이탈률·화면별 체류 시간)\n2. 소셜 로그인 도입 관련 정보보안팀 사전 문의 예정 (검토 기간 최소 2주 예상)\n3. 벤치마킹 자료: 토스증권·카카오페이증권·삼성증권 MTS 회원가입 UX 비교\n\n진강연 사원님께서 고객 데이터 분석 자료(세그먼트별 이탈률, 연령대별 전환율)를\n킥오프 전 공유해 주시면 감사하겠습니다.\n\n많이 바쁘시겠지만 확인 부탁드리겠습니다.\n\n===================================================\n키움증권 채널기획팀  채영희 과장\n\n서울특별시 영등포구 의사당대로 96 (TP타워, 여의도동)\nE-mail : coh0077@kiwoom.com\nTel    : 02-768-3864\n===================================================', E'채영희 과장 (채널기획팀)  <coh0077@kiwoom.com>', E'진강연 사원 (인사이트랩팀); 천규리 과장 (플랫폼전략팀); 제민재 과장 (SQUAD)  <jky0002@kiwoom.com; cgr0774@kiwoom.com; jmj0634@kiwoom.com>', E'신다현 부장 (채널기획팀장); 안홍철 부장 (인사이트랩팀장); 김건 부장 (플랫폼전략팀장); 남재호 차장 (SQUAD장)  <sdh0075@kiwoom.com; ahc0712@kiwoom.com; kg0764@kiwoom.com; njh0633@kiwoom.com>', true, false, false, false, E'2026-04-10 11:20:00+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'5775fd53-d6a3-46e7-a8d8-c19adf934de8', E'1e9dddea-1240-42b9-987a-0f96e866e604', E'd0025145-df46-4e15-adf3-96b660d2cb6c', E'[진행 현황] Sprint 1 완료 — 피처 플래그 API 개발 완료 및 Sprint 2 착수 안내', E'안녕하십니까, SQUAD 제민재입니다. 업무에 노고가 많으십니다.\n\nSprint 1 완료 및 Sprint 2 착수를 알려드립니다.\n\n[Sprint 1 완료 — 피처 플래그 서버 API]\n\n■ 완료 항목\n  · 세그먼트 판별 API: 생년월일 입력 시 세그먼트 키(A/B/C) 반환\n  · 관리 어드민: 세그먼트 기준 수정 및 플래그 On/Off 기능 구현\n  · 천규리 과장님 요청사항 반영: 세그먼트 키 앱 전역 컨텍스트 설계 완료\n  · 스테이징 환경 배포 완료 — 내부 테스트 가능 상태\n\n■ 테스트 안내\n  스테이징 환경에서 세그먼트별 화면 분기를 직접 확인하실 수 있습니다.\n  (접속 방법은 별도 메일로 안내 예정)\n\n[Sprint 2 착수 — 5/5(화)부터]\n  · 세그먼트 A 회원가입 화면 개발 (간편 인증 우선 배치)\n  · 세그먼트 C 회원가입 화면 개발 (큰 글씨·단순 구조)\n  · 약관 동의 화면 세그먼트별 분기 적용\n\n5월 7일 TF 회의에서 스테이징 데모 시연하겠습니다.\n\n많이 바쁘시겠지만 확인 부탁드리겠습니다.\n\n===================================================\n키움증권 SQUAD  제민재 과장\n\n서울특별시 영등포구 의사당대로 96 (TP타워, 여의도동)\nE-mail : jmj0634@kiwoom.com\nTel    : 02-768-5830\n===================================================', E'제민재 과장 (SQUAD)  <jmj0634@kiwoom.com>', E'진강연 사원 (인사이트랩팀); 채영희 과장 (채널기획팀); 천규리 과장 (플랫폼전략팀)  <jky0002@kiwoom.com; coh0077@kiwoom.com; cgr0774@kiwoom.com>', E'남재호 차장 (SQUAD장); 안홍철 부장 (인사이트랩팀장); 신다현 부장 (채널기획팀장); 김건 부장 (플랫폼전략팀장)  <njh0633@kiwoom.com; ahc0712@kiwoom.com; sdh0075@kiwoom.com; kg0764@kiwoom.com>', true, false, false, false, E'2026-05-04 17:20:00+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'64621877-73a9-456f-91cc-648502b9ddf1', E'1e9dddea-1240-42b9-987a-0f96e866e604', E'd0025145-df46-4e15-adf3-96b660d2cb6c', E'[2차 TF 결과] 영웅문 S# UX 개인화 TF — 개발 일정 확정', E'안녕하십니까, SQUAD 제민재입니다. 업무에 노고가 많으십니다.\n\n오늘 2차 TF 회의 결과 및 확정된 개발 일정을 공유드립니다.\n\n[2차 TF 결과 — 2026.04.21]\n\n■ 피처 플래그 인프라: 자체 개발 방식 확정 (천규리 TF장 승인)\n\n■ 확정 개발 일정\n\n  [단기 — 4월 말]\n    · 시니어 큰 글씨 옵션: 4/22(수) 개발 착수 → 4/25(토) 완료 목표\n    · "처음 이용하시나요?" 버튼 UI: 4/23(목) 착수 → 4/28(화) 완료 목표\n    · 약관 동의 UX 개선 (핵심 요약 분리): 추가 확정 → 4/30(목) 완료 목표\n\n  [중기 — Sprint 계획]\n    Sprint 1 (4/22~5/2):  피처 플래그 서버 API 개발\n    Sprint 2 (5/5~5/16):  클라이언트 연동 + 세그먼트 A 화면 개발\n    Sprint 3 (5/19~5/30): 세그먼트 B·C 화면 개발\n    Sprint 4 (6/2~6/13):  QA + 버그 수정\n    Sprint 5 (6/16~6/20): A/B 테스트 셋업 + 스테이징 검증\n    배포 목표: 6/23(화) 운영 반영\n\n■ 다음 TF 회의: 5월 7일(목) 오후 2시\n\n많이 바쁘시겠지만 확인 부탁드리겠습니다.\n\n===================================================\n키움증권 SQUAD  제민재 과장\n\n서울특별시 영등포구 의사당대로 96 (TP타워, 여의도동)\nE-mail : jmj0634@kiwoom.com\nTel    : 02-768-5830\n===================================================', E'제민재 과장 (SQUAD)  <jmj0634@kiwoom.com>', E'진강연 사원 (인사이트랩팀); 채영희 과장 (채널기획팀); 천규리 과장 (플랫폼전략팀)  <jky0002@kiwoom.com; coh0077@kiwoom.com; cgr0774@kiwoom.com>', E'남재호 차장 (SQUAD장); 안홍철 부장 (인사이트랩팀장); 신다현 부장 (채널기획팀장); 김건 부장 (플랫폼전략팀장)  <njh0633@kiwoom.com; ahc0712@kiwoom.com; sdh0075@kiwoom.com; kg0764@kiwoom.com>', true, false, false, false, E'2026-04-21 17:30:00+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'5d0ba783-d424-489f-accc-521e815373d0', E'9ca49754-4b16-45de-ac8f-6a87212c6f01', E'd0025145-df46-4e15-adf3-96b660d2cb6c', E'RE: 영웅문 S# 회원가입·로그인 — 킥오프 확인 및 온보딩 과제 연계 제안', E'안녕하십니까, 플랫폼전략팀 천규리입니다. 업무에 노고가 많으십니다.\n\n4월 14일(화) 오후 2시 참석 가능합니다.\n\n킥오프 전에 추가로 공유드릴 사항이 있어 메일 드립니다.\n\n[플랫폼전략팀 현황 공유]\n현재 저희 팀에서 진행 중인 ''신규 사용자 온보딩 Flow 개선'' 과제 현황입니다.\n\n  · 과제 범위: 가입 완료 후 첫 로그인 ~ 첫 거래까지의 사용자 경험 개선\n  · 현재 진척: UX 현황 분석 완료 / 개선 방향 초안 작성 중\n  · 예상 일정: 5월 내 기획 확정 → 6월 개발 착수\n\n이번 회원가입·로그인 세그먼트 개선과 온보딩 Flow 개선을 연계하면\n사용자가 가입부터 첫 거래까지 일관된 개인화 경험을 제공할 수 있습니다.\n\n킥오프에서 두 과제의 연계 방안도 함께 논의하면 좋겠습니다.\n관련 자료는 회의 당일 공유하겠습니다.\n\n많이 바쁘시겠지만 확인 부탁드리겠습니다.\n\n===================================================\n키움증권 플랫폼전략팀  천규리 과장\n\n서울특별시 영등포구 의사당대로 96 (TP타워, 여의도동)\nE-mail : cgr0774@kiwoom.com\nTel    : 02-768-4004\n===================================================', E'천규리 과장 (플랫폼전략팀)  <cgr0774@kiwoom.com>', E'진강연 사원 (인사이트랩팀); 채영희 과장 (채널기획팀); 제민재 과장 (SQUAD)  <jky0002@kiwoom.com; coh0077@kiwoom.com; jmj0634@kiwoom.com>', E'김건 부장 (플랫폼전략팀장); 안홍철 부장 (인사이트랩팀장); 신다현 부장 (채널기획팀장); 남재호 차장 (SQUAD장)  <kg0764@kiwoom.com; ahc0712@kiwoom.com; sdh0075@kiwoom.com; njh0633@kiwoom.com>', true, false, false, false, E'2026-04-10 14:33:00+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'86418822-d4da-459f-8f5c-590110ebba93', E'4041e00c-b195-4969-80c7-21d52d8c7e93', E'd0025145-df46-4e15-adf3-96b660d2cb6c', E'RE: [문의] 영웅문 S# 회원가입·로그인 화면 고객 세그먼트별 개선 제안', E'안녕하십니까, 채널기획팀 채영희입니다. 업무에 노고가 많으십니다.\n\n진강연 사원님, 상세한 데이터 기반 제안 감사합니다. 채널 기획 관점 의견 공유드립니다.\n\n[채널 기획 관점 검토]\n\n1. 세그먼트 감지 방식\n   · 방안 A: 가입 첫 화면 간접 질문으로 세그먼트 자가 선택 유도\n   · 방안 B: 본인인증(PASS) 완료 후 생년월일 기반 자동 분기\n   → 방안 B가 UX 측면에서 자연스럽고 금융소비자보호법 적합성 확인과도 연계 가능합니다.\n\n2. 소셜 로그인 도입\n   보안정책팀 및 컴플라이언스 사전 협의 필요 — MTS 특성상 주문·결제와 직결되므로\n   별도 추가 인증 레이어가 필요할 수 있습니다.\n\n3. 우선 추진 방향\n   단기: 기존 화면에서 "처음 이용하시나요?" 버튼 강화 + 시니어 전용 큰 글씨 옵션 (최소 공수)\n   중기: 세그먼트 분기 로직 및 UI 전면 개편\n\n많이 바쁘시겠지만 확인 부탁드리겠습니다.\n\n===================================================\n키움증권 채널기획팀  채영희 과장\n\n서울특별시 영등포구 의사당대로 96 (TP타워, 여의도동)\nE-mail : coh0077@kiwoom.com\nTel    : 02-768-3864\n===================================================', E'채영희 과장 (채널기획팀)  <coh0077@kiwoom.com>', E'진강연 사원 (인사이트랩팀); 천규리 과장 (플랫폼전략팀); 제민재 과장 (SQUAD)  <jky0002@kiwoom.com; cgr0774@kiwoom.com; jmj0634@kiwoom.com>', E'신다현 부장 (채널기획팀장); 안홍철 부장 (인사이트랩팀장); 김건 부장 (플랫폼전략팀장); 남재호 차장 (SQUAD장)  <sdh0075@kiwoom.com; ahc0712@kiwoom.com; kg0764@kiwoom.com; njh0633@kiwoom.com>', true, false, false, false, E'2026-04-08 14:15:00+09:00');
INSERT INTO mails (id, from_id, to_id, subject, body, from_text, to_text, cc, is_read, starred, deleted, is_draft, created_at) VALUES (E'37b228a7-0373-4cb3-a646-ea203ba6b11e', E'd0025145-df46-4e15-adf3-96b660d2cb6c', E'a6f10f79-9dc2-4ed7-8b0e-2575d988000c', E'[온보딩 설문] 진강연님 0분기(~1개월) 설문 결과', E'진강연님의 0분기(~1개월) 온보딩 설문 결과입니다.\n\n■ 5점 척도 결과\n• Q1. 팀내 인원들의 이름과 직급을 다 외웠는가: 4점\n• Q2. 사내 메일과 장비들을 받았는가: 4점\n• Q3. 업무를 시작할 환경이 다 갖추어졌는가: 5점\n• 평균: 4.3점\n\n■ 주관식\nQ. 적응해 나아가는 본인의 모습을 상상하여 앞으로의 포부를 간단하게 적어주세요\nA. 2개월동안 힘들었지만 많은 것들을 배울 수 있었습니다. 특히 팀원들과 함께 시간을 보내며 라포를 잘 형성할 수 있었던 것 같습니다. 앞으로는 실전 업무에 배정이 되어 더 많은 업무를 배우고 잘해내가고 싶습니다!\n\n■ AI 분석\n감정: 긍정적이고 희망적인 감정이 느껴집니다. 힘든 과정을 겪었지만, 배움과 팀원들과의 관계 형성에 대한 만족감이 드러납니다.\n\n핵심 키워드: 힘든 경험, 배움, 팀원, 라포 형성, 실전 업무, 포부\n\n요약: 답변자는 2개월 동안 힘든 경험을 통해 많은 것을 배웠으며, 팀원들과의 관계를 잘 형성했다고 느끼고 있습니다. 앞으로 실전 업무에 배정되어 더 많은 업무를 배우고 잘 해내고 싶다는 포부를 가지고 있습니다.  \n📄 출처: 없음', E'진강연 (온보딩 설문 자동 발송)', E'이소현 (인사팀)', E'', true, false, true, false, E'2026-04-09 11:14:38.522746+09:00');
